  assert(obj.visual === 'oven_off', 'visual matches off state');
  assert(obj.timeRemainingMs === null, 'no auto_next timer when off');
});

test('ObjectInstance: character interaction triggers transition', () => {
  const obj = new ObjectInstance(makeOvenDef());
  const event = obj.interact('use');
  assert(event !== null, 'interact returns an event');
  assert(event.from === 'off', 'event.from is off');
  assert(event.to === 'preheating', 'event.to is preheating');
  assert(obj.state === 'preheating', 'oven is now preheating');
  assert(obj.visual === 'oven_glow', 'visual is oven_glow');
  assert(obj.timeRemainingMs === 30000, 'auto_next timer is 30s');
});

test('ObjectInstance: invalid interaction returns null', () => {
  const obj = new ObjectInstance(makeOvenDef());
  obj.interact('use'); // → preheating
  const event = obj.interact('use'); // preheating has no 'use' transition
  assert(event === null, 'no valid transition returns null');
});

test('ObjectInstance: auto_next timer fires', () => {
  const obj = new ObjectInstance(makeOvenDef());
  obj.interact('use'); // → preheating

  // Tick for less than 30s — no transition
  let event = obj.tick(15000);
  assert(event === null, 'no transition before timer expires');
  assert(obj.state === 'preheating', 'still preheating');
  assert(obj.timer === 15000, 'timer advanced');

  // Tick past the 30s mark
  event = obj.tick(16000); // total: 31s
  assert(event !== null, 'transition fires after timer expires');
  assert(event.from === 'preheating', 'from preheating');
  assert(event.to === 'baking', 'to baking');
  assert(event.trigger === 'auto', 'trigger is auto');
  assert(obj.state === 'baking', 'oven is now baking');
});

test('ObjectInstance: full auto-transition chain (preheating → baking → done → burnt)', () => {
  const obj = new ObjectInstance(makeOvenDef());
  obj.interact('use'); // → preheating

  // preheating → baking (30s)
  obj.tick(30000);
  assert(obj.state === 'baking', 'preheating → baking after 30s');

  // baking → done (60s)
  obj.tick(60000);
  assert(obj.state === 'done', 'baking → done after 60s');

  // done → burnt (30s)
  obj.tick(30000);
  assert(obj.state === 'burnt', 'done → burnt after 30s');

  // burnt has no auto_next — stays burnt
  obj.tick(60000);
  assert(obj.state === 'burnt', 'burnt stays burnt (no auto_next)');
});

test('ObjectInstance: interaction at done state prevents burning', () => {
  const obj = new ObjectInstance(makeOvenDef());
  obj.interact('use'); // → preheating
  obj.tick(30000);     // → baking
  obj.tick(60000);     // → done

  // Character takes the bread before it burns
  const event = obj.interact('use');
  assert(event !== null, 'interaction at done succeeds');
  assert(event.to === 'off', 'oven returns to off');
  assert(event.produces === 'bread', 'produces bread');
  assert(event.target === 'bakery_display_case', 'target is display case');
  assert(obj.state === 'off', 'oven is off');
});

test('ObjectEngine: tick advances all objects', () => {
  const engine = new ObjectEngine();
  engine.addObject(makeOvenDef());
  engine.addObject(makeDisplayCaseDef());

  // Start the oven
  engine.interact('bakery_oven', 'use'); // → preheating

  // Tick — only oven has a timer
  let events = engine.tick(30000);
  assert(events.length === 1, 'one transition event');
  assert(events[0].objectId === 'bakery_oven', 'event is from oven');
  assert(events[0].to === 'baking', 'oven transitioned to baking');
});

test('ObjectEngine: production side-effect (oven → display case)', () => {
  const engine = new ObjectEngine();
  engine.addObject(makeOvenDef());
  engine.addObject(makeDisplayCaseDef());

  // Run oven through to done
  engine.interact('bakery_oven', 'use'); // → preheating
  engine.tick(30000);                     // → baking
  engine.tick(60000);                     // → done

  // Character takes bread out
  const event = engine.interact('bakery_oven', 'use');
  assert(event.produces === 'bread', 'oven produces bread');

  // Check display case got the bread
  const display = engine.get('bakery_display_case');
  assert(display.state === 'bread', 'display case now has bread');
});

test('ObjectEngine: event listeners fire', () => {
  const engine = new ObjectEngine();
  engine.addObject(makeOvenDef());

  const received = [];
  engine.onTransition((event) => received.push(event));

  engine.interact('bakery_oven', 'use'); // → preheating
  assert(received.length === 1, 'listener received interaction event');
  assert(received[0].to === 'preheating', 'event has correct target state');

  engine.tick(30000); // → baking
  assert(received.length === 2, 'listener received auto-transition event');
});

test('ObjectEngine: getBySector filters correctly', () => {
  const engine = new ObjectEngine();
  engine.addObject(makeOvenDef());
  engine.addObject(makeDisplayCaseDef());
  engine.addObject({
    id: 'studio_easel',
    name: 'easel',
    sector: 'studio',
    arena: 'workspace',
    position: { x: 400, y: 430 },
    state: 'blank',
    states: { blank: { visual: 'easel_blank' } },
  });

  const bakeryObjects = engine.getBySector('bakery');
  assert(bakeryObjects.length === 2, 'bakery has 2 objects');

  const studioObjects = engine.getBySector('studio');
  assert(studioObjects.length === 1, 'studio has 1 object');
});

test('ObjectEngine: snapshot returns all object states', () => {
  const engine = new ObjectEngine();
  engine.addObject(makeOvenDef());
  engine.addObject(makeDisplayCaseDef());

  const snap = engine.snapshot();
  assert('bakery_oven' in snap, 'snapshot has oven');
  assert('bakery_display_case' in snap, 'snapshot has display case');
  assert(snap.bakery_oven.state === 'off', 'oven state is off');
  assert(snap.bakery_display_case.state === 'empty', 'display case is empty');
});

test('ObjectInstance: timeRemainingMs tracks correctly', () => {
  const obj = new ObjectInstance(makeOvenDef());
  obj.interact('use'); // → preheating, 30s timer
  assert(obj.timeRemainingMs === 30000, 'full 30s remaining');

  obj.tick(10000);
  assert(obj.timeRemainingMs === 20000, '20s remaining after 10s tick');

  obj.tick(10000);
  assert(obj.timeRemainingMs === 10000, '10s remaining after 20s total');
});

