// ═══════════════════════════════════════════════════════════
// AI Decision Engine — LLM-driven character decisions
// ═══════════════════════════════════════════════════════════
//
// Sits on top of the existing wander system. When enabled,
// characters make decisions via the AI API instead of wandering
// randomly. Falls back to random wander on failure/timeout.

import { AIClient } from './api.js';
import { findInteractTile } from './characters.js';
import { SECTORS } from './world.js';

const STAGGER_MS = 12000;
const COOLDOWN_MIN = 30000;
const COOLDOWN_MAX = 60000;

export class AIDecisionEngine {
  constructor(options = {}) {
    this.client = new AIClient({
      endpoint: options.endpoint || '',
      timeoutMs: options.timeoutMs || 15000,
    });
    this.engine = null;
    this.charState = new Map();
    this.pendingMessages = new Map(); // charId → [{ from, dialogue }]
  }

  /** Link to the simulation engine (called once during setup). */
  attach(engine) {
    this.engine = engine;
    this.charState.clear();
    this.pendingMessages.clear();
    engine.characters.forEach((char, i) => {
      this.charState.set(char.id, {
        cooldownMs: 5000 + i * STAGGER_MS,
        pending: false,
      });
    });
  }

  setEndpoint(url) {
    this.client.endpoint = url;
  }

  get endpoint() {
    return this.client.endpoint;
  }

  /** Returns true if this character has a pending AI decision. */
  isPending(charId) {
    return this.charState.get(charId)?.pending || false;
  }

  /** Called each engine tick for each idle character. */
  tick(char, deltaMs) {
    const state = this.charState.get(char.id);
    if (!state || state.pending) return;

    state.cooldownMs -= deltaMs;
    if (state.cooldownMs > 0) return;

    state.cooldownMs = COOLDOWN_MIN + Math.random() * (COOLDOWN_MAX - COOLDOWN_MIN);
    state.pending = true;

    this._requestDecision(char).catch(() => {});
  }

  async _requestDecision(char) {
    const state = this.charState.get(char.id);
    const engineRef = this.engine;

    try {
      if (!this.client.endpoint) {
        throw new Error('No API endpoint configured');
      }

      const objects = engineRef.objectEngine.getAll();
      const characters = engineRef.characters;
      const perception = char.getPerception(objects, characters);

      // Attach pending messages from other characters
      const messages = this.pendingMessages.get(char.id);
      if (messages && messages.length > 0) {
        perception.recentMessages = messages.slice();
        this.pendingMessages.delete(char.id);
      }

      const decision = await this.client.decide({
        character: char.name,
        personality: char.personality,
        perception,
        mood: char.mood,
        energy: char.energy,
        time: engineRef.simClock.timeString,
        day: engineRef.simClock.day,
      });

      // Engine might have been reset while we waited
      if (this.engine !== engineRef) return;
      if (char.action !== 'idle') return;

      this._executeDecision(char, decision);
    } catch (err) {
      if (this.engine !== engineRef) return;
      console.warn(`AI decision failed for ${char.name}:`, err.message || err);
      if (char.action === 'idle') {
        engineRef._randomWander(char);
      }
    } finally {
      state.pending = false;
    }
  }

  _executeDecision(char, decision) {
    if (!decision || !decision.action) return;

    const engine = this.engine;
    const objects = engine.objectEngine.getAll();
    const characters = engine.characters;

    // Emit description for status bar
    if (decision.description) {
      engine._emit('ai:status', {
        characterName: char.name,
        description: decision.description,
      });
    }

    switch (decision.action) {
      case 'interact': {
        const obj = this._resolveObject(decision.target, objects);
        if (!obj) {
          engine._randomWander(char);
          return;
        }

        const tile = findInteractTile(obj.position);
        if (!tile) {
          engine._randomWander(char);
          return;
        }

        const atTarget = tile.tx === Math.round(char.tx) && tile.ty === Math.round(char.ty);
        if (atTarget) {
          engine._doInteraction(char, obj, 'use');
        } else if (char.moveTo(tile.tx, tile.ty)) {
          char.targetObjectId = obj.id;
          char.pendingAction = 'use';
        }

        if (decision.dialogue) {
          engine._emit('ai:speech', { characterId: char.id, dialogue: decision.dialogue });
        }
        break;
      }

      case 'move': {
        const sector = this._resolveSector(decision.target);
        if (sector) {
          const ox = Math.floor(Math.random() * 3) - 1;
          const oy = Math.floor(Math.random() * 3) - 1;
          char.moveTo(sector.tx + ox, sector.ty + oy);
        }

        if (decision.dialogue) {
          engine._emit('ai:speech', { characterId: char.id, dialogue: decision.dialogue });
        }
        break;
      }

      case 'talk': {
        const target = characters.find(c =>
          c.id !== char.id && (
            c.name.toLowerCase() === (decision.target || '').toLowerCase() ||
            c.id === (decision.target || '').toLowerCase()
          )
        );

        if (decision.dialogue) {
          engine._emit('ai:speech', { characterId: char.id, dialogue: decision.dialogue });
        }

        if (target) {
          // Queue message for target's next decision
          if (!this.pendingMessages.has(target.id)) {
            this.pendingMessages.set(target.id, []);
          }
          this.pendingMessages.get(target.id).push({
            from: char.name,
            dialogue: decision.dialogue || '',
          });

          // Move toward the target if far away
          const dist = Math.abs(char.tx - target.tx) + Math.abs(char.ty - target.ty);
          if (dist > 2) {
            const adjTile = findInteractTile({
              tx: Math.round(target.tx), ty: Math.round(target.ty), tw: 1, th: 1,
            });
            if (adjTile) char.moveTo(adjTile.tx, adjTile.ty);
          }

          // Bump target's cooldown so they respond sooner
          const targetState = this.charState.get(target.id);
          if (targetState && !targetState.pending) {
            targetState.cooldownMs = Math.min(targetState.cooldownMs, 8000 + Math.random() * 4000);
          }
        }
        break;
      }

      case 'idle': {
        // Character stays put — just show dialogue
        if (decision.dialogue) {
          engine._emit('ai:speech', { characterId: char.id, dialogue: decision.dialogue });
        }
        break;
      }

      default:
        engine._randomWander(char);
    }
  }

  _resolveObject(target, objects) {
    if (!target) return null;
    const lower = target.toLowerCase();
    const underscored = lower.replace(/\s+/g, '_');
    return objects.find(o => o.id === target) ||
      objects.find(o => o.id === underscored) ||
      objects.find(o => o.name.toLowerCase() === lower) ||
      objects.find(o => o.id.endsWith(underscored)) ||
      objects.find(o => o.name.toLowerCase().includes(lower)) ||
      null;
  }

  _resolveSector(target) {
    if (!target) return null;
    const lower = target.toLowerCase();
    if (SECTORS[lower]) return SECTORS[lower];
    return Object.values(SECTORS).find(s =>
      s.name.toLowerCase() === lower
    ) || null;
  }
}

