diff --git a/src/ai.js b/src/ai.js
index 2a386ab..006cea9 100644
--- a/src/ai.js
+++ b/src/ai.js
@@ -190,13 +190,20 @@ export class AIDecisionEngine {
             dialogue: decision.dialogue || '',
           });

-          // Move toward the target if far away
+          // Move toward the target if far away, or face each other if already close
           const dist = Math.abs(char.tx - target.tx) + Math.abs(char.ty - target.ty);
           if (dist > 2) {
             const adjTile = findInteractTile({
               tx: Math.round(target.tx), ty: Math.round(target.ty), tw: 1, th: 1,
             });
-            if (adjTile) char.moveTo(adjTile.tx, adjTile.ty);
+            if (adjTile) {
+              char.moveTo(adjTile.tx, adjTile.ty);
+              char.targetCharId = target.id;
+            }
+          } else {
+            // Already nearby — face each other immediately
+            char._updateFacing(target.tx - char.tx, target.ty - char.ty);
+            target._updateFacing(char.tx - target.tx, char.ty - target.ty);
           }

           // Bump target's cooldown so they respond sooner
diff --git a/src/characters.js b/src/characters.js
index a526a5e..be28682 100644
--- a/src/characters.js
+++ b/src/characters.js
@@ -138,6 +138,7 @@ export class Character {
     // Interaction tracking
     this.lastObjectId = null;
     this.pendingAction = 'use';
+    this.targetCharId = null;   // ID of a character to face toward upon arrival

     // Mood system
     this.mood = 'content';       // happy | content | neutral | upset
diff --git a/src/engine.js b/src/engine.js
index 4ff7a3d..f19fe45 100644
--- a/src/engine.js
+++ b/src/engine.js
@@ -285,14 +285,24 @@ export class SimulationEngine {
       char.update(deltaMs);

       // Character just arrived at destination
-      if (wasWalking && char.action === 'idle' && char.targetObjectId) {
-        const obj = this.objectEngine.get(char.targetObjectId);
-        if (obj) {
-          this._doInteraction(char, obj, char.pendingAction || 'use');
-        } else {
-          char.targetObjectId = null;
+      if (wasWalking && char.action === 'idle') {
+        if (char.targetObjectId) {
+          const obj = this.objectEngine.get(char.targetObjectId);
+          if (obj) {
+            this._doInteraction(char, obj, char.pendingAction || 'use');
+          } else {
+            char.targetObjectId = null;
+          }
+          char.pendingAction = 'use';
+        } else if (char.targetCharId) {
+          // Character arrived near another character for conversation — face each other
+          const target = this.characters.find(c => c.id === char.targetCharId);
+          if (target) {
+            char._updateFacing(target.tx - char.tx, target.ty - char.ty);
+            target._updateFacing(char.tx - target.tx, char.ty - target.ty);
+          }
+          char.targetCharId = null;
         }
-        char.pendingAction = 'use';
       }
     }
   }

